mapper.select:
SELECT a.id, a.plan_id, a.adjust_reason, a.adjust_type, a.before_data, a.after_data, a.status, a.applied_by, a.applied_at, a.audited_by, a.audited_at, a.audit_remark, a.org_id, a.tenant_id, a.created_at, a.updated_at, a.deleted, p.plan_code, p.plan_date FROM recipe_plan_adjustment a LEFT JOIN recipe_plan p ON a.plan_id = p.id WHERE a.deleted = 0
AND a.plan_id = #{planId}
AND a.status = #{status}
ORDER BY a.created_at DESC
